+        return Err(IdValidationError::InvalidStartChar { ch: first });
+    }
+
+    for (index, ch) in chars {
+        let ok =
+            ch.is_ascii_lowercase() || ch.is_ascii_digit() || matches!(ch, '.' | '_' | ':' | '-');
+        if !ok {
+            return Err(IdValidationError::InvalidChar { ch, index });
